/*
 * aes_stub.c — AES-128-CTR runtime decryption stub (shared by strenc + vmpass).
 *
 * Public entry points:
 *   __aes_decrypt()       — used by strenc (reconstructs key from providers)
 *   __obf_aes_ctr_decrypt()  — used by vmpass (caller supplies expanded key)
 *
 * Both passes link this same bitcode; the linker-level dedup check in
 * This file is compiled to LLVM bitcode during the LLVM build and embedded
 * as a byte array inside StringEncryption.cpp.  At pass runtime, the bitcode
 * is parsed, patched with the key-provider bodies generated by the pass, and
 * linked into the target module so that all subsequent obfuscation passes
 * (flattening, MBA, BCF, adec …) also cover the decryption stub.
 *
 * ── Key interface ──────────────────────────────────────────────────────────
 *
 *  The pass generates two "key provider" IR functions whose bodies contain
 *  the compile-time AES round-key material:
 *
 *    void __aes_key_a(uint8_t out[88])   ← memcpy from .strenc.kd global
 *    void __aes_key_b(uint8_t out[88])   ← 88 individual store immediates
 *                                              in .strenc.kt code section
 *
 *  Both are declared extern here; their definitions are injected by the pass
 *  after linking this stub module into the target module.
 *
 * ── Call site interface ────────────────────────────────────────────────────
 *
 *    void __aes_decrypt(uint8_t *buf, uint32_t len, const uint8_t *nonce8)
 *
 *  buf    : stack buffer pre-filled with the ciphertext (modified in-place).
 *  len    : plaintext length (does NOT include the null terminator byte).
 *  nonce8 : 8-byte per-string nonce (unique per string index + content hash).
 *
 * ── Segments ──────────────────────────────────────────────────────────────
 *
 *  __aes_decrypt and helpers → default .text / __TEXT,__text
 *  __aes_key_a               → generated by pass, memcpy from .strenc.kd
 *  __aes_key_b               → generated by pass, stores in .strenc.kt
 *
 * ── Compile flags used by CMakeLists ──────────────────────────────────────
 *
 *   clang -O2 -emit-llvm -c -ffreestanding -fno-builtin-memcpy
 *         -fno-builtin-memset -fvisibility=hidden
 *
 * IMPORTANT: No string literals anywhere in this file — the strenc pass
 * itself would try to re-encrypt them, causing double-encryption bugs.
 */

#include <stdint.h>

/* ── key providers declared extern, bodies injected by pass ──────────────── */
extern void __aes_key_a(uint8_t out[88]);
extern void __aes_key_b(uint8_t out[88]);

/* ── portable minimal memcpy / memset (avoid builtin; -ffreestanding) ────── */
static void se_memcpy(void *dst, const void *src, uint32_t n) {
    uint8_t       *d = (uint8_t *)dst;
    const uint8_t *s = (const uint8_t *)src;
    for (uint32_t i = 0; i < n; i++) d[i] = s[i];
}
static void se_memset(void *dst, uint8_t v, uint32_t n) {
    uint8_t *d = (uint8_t *)dst;
    for (uint32_t i = 0; i < n; i++) d[i] = v;
}

/* ── AES-128 lookup tables ───────────────────────────────────────────────── */

