/* ── AES GF(2^8) multiply by 2 (xtime) ──────────────────────────────────── */
static inline uint8_t xtime(uint8_t x) {
    return (uint8_t)((x << 1) ^ ((x >> 7) * 0x1bu));
}

/* ── AES ShiftRows (in-place, column-major layout) ───────────────────────── */
/*
 * AES state layout: s[col*4 + row]
 *   col 0  col 1  col 2  col 3
 *   s[0]   s[4]   s[8]   s[12]    row 0 — no shift
 *   s[1]   s[5]   s[9]   s[13]    row 1 — left-shift 1
 *   s[2]   s[6]   s[10]  s[14]    row 2 — left-shift 2
 *   s[3]   s[7]   s[11]  s[15]    row 3 — left-shift 3
 */
static void aes_shift_rows(uint8_t s[16]) {
    uint8_t t;
    /* row 1: rotate left by 1 */
    t = s[1]; s[1] = s[5]; s[5] = s[9]; s[9] = s[13]; s[13] = t;
    /* row 2: rotate left by 2 */
    t = s[2]; s[2] = s[10]; s[10] = t;
    t = s[6]; s[6] = s[14]; s[14] = t;
    /* row 3: rotate left by 3  (= right by 1) */
    t = s[15]; s[15] = s[11]; s[11] = s[7]; s[7] = s[3]; s[3] = t;
}

/* ── AES MixColumns (in-place) ───────────────────────────────────────────── */
static void aes_mix_columns(uint8_t s[16]) {
    for (int c = 0; c < 4; c++) {
        uint8_t a = s[c*4+0], b = s[c*4+1], cc = s[c*4+2], d = s[c*4+3];
        uint8_t tmp = a ^ b ^ cc ^ d;
        s[c*4+0] ^= tmp ^ xtime((uint8_t)(a ^ b));
        s[c*4+1] ^= tmp ^ xtime((uint8_t)(b ^ cc));
        s[c*4+2] ^= tmp ^ xtime((uint8_t)(cc ^ d));
        s[c*4+3] ^= tmp ^ xtime((uint8_t)(d ^ a));
    }
}

/* ── AES-128 encrypt one 16-byte block ───────────────────────────────────── */
/*
 * rk   : 176-byte expanded key schedule (11 round keys × 16 bytes)
 * block: 16-byte block encrypted in-place
 *
 * NOTE: This is NOT static — __obf_aes_ctr_decrypt needs it, and keeping it
 * as a single definition avoids code duplication when LTO merges strenc + vmpass.
 */
static void aes128_encrypt_block(const uint8_t rk[176], uint8_t block[16]) {
    uint8_t s[16];
    se_memcpy(s, block, 16);

    /* AddRoundKey — round 0 */
    for (int i = 0; i < 16; i++) s[i] ^= rk[i];

    /* Rounds 1–9: SubBytes, ShiftRows, MixColumns, AddRoundKey */
    for (int r = 1; r <= 9; r++) {
        for (int i = 0; i < 16; i++) s[i] = SE_SBOX[s[i]];
        aes_shift_rows(s);
        aes_mix_columns(s);
        for (int i = 0; i < 16; i++) s[i] ^= rk[r*16 + i];
    }

    /* Round 10: SubBytes, ShiftRows, AddRoundKey (no MixColumns) */
    for (int i = 0; i < 16; i++) s[i] = SE_SBOX[s[i]];
    aes_shift_rows(s);
    for (int i = 0; i < 16; i++) s[i] ^= rk[160 + i];

    se_memcpy(block, s, 16);
}

/* ── CTR counter increment ─ */
static inline void ctr_inc(uint8_t ctr[16]) {
    for (int i = 15; i >= 8; i--) { if (++ctr[i]) break; }
}


/*
* __obf_aes_ctr_decrypt  —  Shared AES-CTR decryption with caller-provided key.
*
* This is the common decryption primitive used by both strenc (indirectly via
* __strenc_decrypt) and vmpass (directly from the .init_array constructor).
*
* buf       : buffer to decrypt in-place.
* len       : number of bytes to process.
* rk176     : pointer to the full 176-byte expanded AES-128 round-key schedule.
* nonce8    : 8-byte nonce; counter block = nonce8 || 0x00{8}.
*
* When strenc and vmpass are both active, this function exists exactly once in
* the binary — the linker-level check in linkStub() deduplicates the bitcode.
* ═══════════════════════════════════════════════════════════════════════════ */
__attribute__((noinline))
void __obf_aes_ctr_decrypt(uint8_t *buf, uint32_t len,
                            const uint8_t *rk176, const uint8_t *nonce8) {
    uint8_t ctr[16];
    se_memcpy(ctr, nonce8, 8);
    se_memset(ctr + 8, 0, 8);

    uint32_t offset = 0;
    while (offset < len) {
        uint8_t ks[16];
        se_memcpy(ks, ctr, 16);
        aes128_encrypt_block(rk176, ks);

        uint32_t n = (len - offset < 16u) ? (len - offset) : 16u;
        for (uint32_t i = 0; i < n; i++)
            buf[offset + i] ^= ks[i];

        offset += 16u;
        ctr_inc(ctr);
    }
}


/* ═══════════════════════════════════════════════════════════════════════════
 * __strenc_decrypt
 *
 * Primary entry point injected at each string use-site by the pass.
 *
 * buf    : stack buffer, pre-filled with ciphertext, decrypted in-place.
 * len    : plaintext byte count (does NOT include the null terminator).
 * nonce8 : 8-byte nonce — unique per string (FNV-64 of index + content).
 *
 * Counter block layout:  | nonce8 (8 bytes) | counter64_be (8 bytes, = 0) |
 * Counter increments in big-endian in the upper 8 bytes after each block.
 * ═══════════════════════════════════════════════════════════════════════════ */
__attribute__((noinline))
void __aes_decrypt(uint8_t *buf, uint32_t len, const uint8_t *nonce8) {
    /* ── 1. Recombine key halves → 176-byte round-key schedule ── */
    uint8_t ha[88], hb[88], rk[176];
    __aes_key_a(ha);          /* first 88 bytes  — from data segment  */
    __aes_key_b(hb);          /* second 88 bytes — from code segment  */
    se_memcpy(rk,      ha, 88);
    se_memcpy(rk + 88, hb, 88);

    /* —— 2. Delegate to the shared CTR routine —— */
    __obf_aes_ctr_decrypt(buf, len, rk, nonce8);
}